output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?novel ?novelLabel ?era ?eraLabel WHERE {
  ?novel wdt:P50 wd:Q38337 .
  ?novel wdt:P31 wd:Q82622 .
  ?novel wdt:P1191 ?era .
  OPTIONAL {
    ?novel rdfs:label ?novelLabel
    FILTER(LANG(?novelLabel) = "en")
  }
  OPTIONAL {
    ?era rdfs:label ?eraLabel
    FILTER(LANG(?eraLabel) = "en")
  }
}
